<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      chunkStrategy: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;renderer&#39;</span></span>
